/**
 * Sanity Studio embedded page — fully client-rendered.
 * Loads the Studio React app in the browser; no SSR needed.
 */
---

<!doctype html>
<html lang="en">
  <head>
    <meta charset="UTF-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1.0" />
    <title>FICCC Studio</title>
    <style>
      html, body, #studio-root {
        margin: 0;
        padding: 0;
        height: 100%;
        width: 100%;
        overflow: hidden;
      }
    </style>
  </head>
  <body>
    <div id="studio-root"></div>
    <script>
      import { StudioProvider, StudioLayout } from 'sanity';
      import { createRoot } from 'react-dom/client';
      import { createElement } from 'react';
      import config from '../../../sanity.config';

      const root = createRoot(document.getElementById('studio-root'));
      root.render(
        createElement(StudioProvider, { config },
          createElement(StudioLayout)
        )
      );
    </script>
  </body>
</html>

import { StudioProvider, StudioLayout } from 'sanity';
import config from '../../sanity.config';

export default function Studio() {
  return (
    <StudioProvider config={config}>
      <StudioLayout />
    </StudioProvider>
  );
}

